char const* parse_int(char const* start, char const* end, char delimiter, boost::int64_t& val)
{
	const boost::int64_t max_val = 9223372036854775807LL; // INT64_MAX
	const boost::int64_t max_val_div_10 = max_val / 10;
	const int max_val_mod_10 = max_val % 10;

	while (start < end && *start != delimiter)
	{
		if (!is_digit(*start)) { return 0; }
		int digit = *start - '0';

		// Check for overflow before multiplication and addition
		if (val > max_val_div_10 || (val == max_val_div_10 && digit > max_val_mod_10))
		{
			return 0; // overflow detected
		}

		val *= 10;
		val += digit;
		++start;
	}
	return start;
}

